"""sklearn.inspection — Model inspection utilities."""
import numpy as np


def permutation_importance(estimator, X, y, *, scoring=None, n_repeats=5,
                           n_jobs=None, random_state=None, sample_weight=None,
                           max_samples=1.0):
    """Compute permutation feature importance.

    For each feature, shuffle the column n_repeats times and measure
    the drop in score compared to the baseline.

    Parameters
    ----------
    estimator : fitted estimator
    X : array-like of shape (n_samples, n_features)
    y : array-like
    scoring : callable or None
        If None, uses estimator.score.
    n_repeats : int, default=5
    n_jobs : ignored (kept for API compat)
    random_state : int or None
    sample_weight : ignored (kept for API compat)
    max_samples : float, default=1.0
        Fraction of samples to use for computing importance.

    Returns
    -------
    result : Bunch with importances_mean, importances_std, importances
    """
    from sklearn.utils import Bunch
    if isinstance(random_state, np.random.RandomState):
        rng = random_state
    elif isinstance(random_state, (int, np.integer)):
        rng = np.random.RandomState(random_state)
    else:
        rng = np.random.RandomState()

    X = np.asarray(X, dtype=float)
    y = np.asarray(y)

    n_samples = X.shape[0]
    if isinstance(max_samples, float) and max_samples < 1.0:
        n_sub = max(1, int(max_samples * n_samples))
        sub_idx = rng.choice(n_samples, size=n_sub, replace=False)
        X_eval = X[sub_idx]
        y_eval = y[sub_idx]
    else:
        X_eval = X
        y_eval = y

    if scoring is None:
        baseline = estimator.score(X_eval, y_eval)
        def scorer(est, Xv, yv):
            return est.score(Xv, yv)
    else:
        baseline = scoring(estimator, X_eval, y_eval)
        scorer = scoring

    n_features = X_eval.shape[1]
    importances = np.zeros((n_features, n_repeats))
    for j in range(n_features):
        for r in range(n_repeats):
            X_perm = X_eval.copy()
            X_perm[:, j] = rng.permutation(X_perm[:, j])
            score_perm = scorer(estimator, X_perm, y_eval)
            importances[j, r] = baseline - score_perm

    return Bunch(
        importances_mean=importances.mean(axis=1),
        importances_std=importances.std(axis=1),
        importances=importances,
    )


def partial_dependence(estimator, X, features, *, categorical_features=None,
                       feature_names=None, response_method='auto',
                       percentiles=(0.05, 0.95), grid_resolution=100,
                       method='auto', kind='average'):
    """Compute partial dependence of ``features``.

    For each feature (or pair), create a grid of values and compute
    the average model prediction over the grid (marginalizing over
    the other features).

    Parameters
    ----------
    estimator : fitted estimator
    X : array-like of shape (n_samples, n_features)
    features : list of int or list of (int, int)
        Feature indices to compute partial dependence for.
    categorical_features : ignored
    feature_names : ignored
    response_method : str, default='auto'
        'auto' tries predict_proba, then decision_function, then predict.
    percentiles : tuple of float, default=(0.05, 0.95)
    grid_resolution : int, default=100
    method : str, default='auto'
    kind : str, default='average'
        'average' for averaged PD, 'individual' for ICE, 'both'.

    Returns
    -------
    result : Bunch with 'average', 'individual' (if requested),
             'values' (alias grid_values)
    """
    from sklearn.utils import Bunch

    X = np.asarray(X, dtype=float)
    n_samples = X.shape[0]

    # Determine prediction function
    if response_method == 'auto':
        if hasattr(estimator, 'predict_proba'):
            predict_fn = estimator.predict_proba
        elif hasattr(estimator, 'decision_function'):
            predict_fn = estimator.decision_function
        else:
            predict_fn = estimator.predict
    elif response_method == 'predict_proba':
        predict_fn = estimator.predict_proba
    elif response_method == 'decision_function':
        predict_fn = estimator.decision_function
    else:
        predict_fn = estimator.predict

    # Normalize features to a list of tuples/ints
    if isinstance(features, (int, np.integer)):
        features = [features]
    if not isinstance(features, (list, tuple)):
        features = list(features)

    results_avg = []
    results_ind = []
    results_values = []

    for feat in features:
        if isinstance(feat, (int, np.integer)):
            # Single feature PD
            feat_idx = int(feat)
            lo = np.percentile(X[:, feat_idx], percentiles[0] * 100)
            hi = np.percentile(X[:, feat_idx], percentiles[1] * 100)
            grid = np.linspace(lo, hi, grid_resolution)

            individual = np.zeros((n_samples, grid_resolution))
            for g_i, val in enumerate(grid):
                X_mod = X.copy()
                X_mod[:, feat_idx] = val
                preds = predict_fn(X_mod)
                if preds.ndim == 2:
                    # Multi-class: use column 1 for binary, or all columns
                    if preds.shape[1] == 2:
                        preds = preds[:, 1]
                    else:
                        preds = preds[:, 1]  # Default to class 1
                individual[:, g_i] = preds

            avg = individual.mean(axis=0).reshape(1, -1)
            results_avg.append(avg)
            results_ind.append(individual)
            results_values.append(grid)

        elif isinstance(feat, (list, tuple)) and len(feat) == 2:
            # Pair of features (2D PD)
            f0, f1 = int(feat[0]), int(feat[1])
            lo0 = np.percentile(X[:, f0], percentiles[0] * 100)
            hi0 = np.percentile(X[:, f0], percentiles[1] * 100)
            lo1 = np.percentile(X[:, f1], percentiles[0] * 100)
            hi1 = np.percentile(X[:, f1], percentiles[1] * 100)
            grid0 = np.linspace(lo0, hi0, grid_resolution)
            grid1 = np.linspace(lo1, hi1, grid_resolution)

            avg = np.zeros((grid_resolution, grid_resolution))
            for i, v0 in enumerate(grid0):
                for j, v1 in enumerate(grid1):
                    X_mod = X.copy()
                    X_mod[:, f0] = v0
                    X_mod[:, f1] = v1
                    preds = predict_fn(X_mod)
                    if preds.ndim == 2:
                        preds = preds[:, 1] if preds.shape[1] == 2 else preds[:, 1]
                    avg[i, j] = preds.mean()

            results_avg.append(avg.reshape(1, grid_resolution, grid_resolution))
            results_ind.append(None)
            results_values.append([grid0, grid1])

    # Build result
    if len(features) == 1:
        avg_out = results_avg[0]
        ind_out = results_ind[0]
        vals_out = results_values
    else:
        avg_out = results_avg
        ind_out = results_ind
        vals_out = results_values

    result = Bunch(
        average=avg_out,
        grid_values=vals_out,
        values=vals_out,
    )
    if kind in ('individual', 'both'):
        result['individual'] = ind_out
    return result
